configfiles.configfile:
## "#raw" is a galaxy cheetah template dirrective that tells galaxy to not interpret
## anything between these tags as template syntax and treat as a plain text.
## without "#raw", galaxy would try to interpret R symbols as its own language and break the R script.  
#raw
suppressPackageStartupMessages({
    library(recount3)
    library(recount)
    library(SummarizedExperiment)
})

args <- commandArgs(trailingOnly = TRUE)
data_source <- args[1]
tissue_type <- args[2]
out_raw <- args[3]
out_tpm <- args[4]
out_sample <- args[5]
out_gene <- args[6]
normalize <- as.logical(args[7])
options(timeout = 600)

## writes a data frame to a tab-delimited file with row names and no quotes
write_tab <- function(x, path) {
    write.table(x, path, sep = "\t", quote = FALSE, row.names = TRUE, col.names = NA)
}


## returns the first column name in `data` that matches any of the `candidates`,
## or NULL if no match is found
first_col <- function(data, candidates) {
    hits <- candidates[candidates %in% colnames(data)]
    if (length(hits)) hits[1] else NULL
}

## filters a recount3 RSE to tumor, normal, or both sample types based on the `tissue_type` argument
filter_tcga <- function(rse, tissue_type) {
    if (tissue_type == "both") return(rse)

## TCGA sample type is stored in different columns in different recount3 versions, so we look for multiple candidates
    meta <- as.data.frame(colData(rse))
    type_col <- first_col(meta, c(
        "tcga.cgc_sample_sample_type", ## most common column name for TCGA sample type in recount3
        "tcga.gdc_cases.samples.sample_type" ## fallback column name for older recount3 versions (e.g. v1.20.0)
    ))

    if (is.null(type_col)) {
        cat("WARNING: no TCGA sample-type column found; returning all samples.\n")
        return(rse)
    }

    pattern <- if (tissue_type == "tumor") "tumor" else "normal"
    keep <- grepl(pattern, as.character(meta[[type_col]]), ignore.case = TRUE)
    if (!any(keep)) stop("No ", tissue_type, " samples found for ", data_source)

    cat("TCGA filter:", tissue_type, "using", type_col, "- kept", sum(keep), "samples\n")
    rse[, keep, drop = FALSE]
}

use_tcga_barcodes <- function(rse) {
    meta <- as.data.frame(colData(rse))
    barcode_col <- first_col(meta, c(
        "tcga.tcga_barcode", ## most common column name for TCGA barcode in recount3
        "tcga.gdc_cases.samples.submitter_id", ## fallback column name for older recount3 versions (e.g. v1.20.0)
        "tcga.cgc_sample_id",
        "tcga_barcode"
    ))

    if (!is.null(barcode_col)) {
        colnames(rse) <- make.unique(as.character(meta[[barcode_col]]), sep = "_")
        cat("TCGA sample names set from", barcode_col, "\n")
        return(rse)
    }   else {
        cat("WARNING: no TCGA barcode column found; keeping UUID sample names.\n")
    }

    barcodes <- as.character(meta[[barcode_col]])
    bad <- is.na(barcodes) | barcodes == "" | barcodes == "NA"
    if (any(bad)) {
        cat("WARNING: barcode column has missing values; keeping UUID sample names.\n")
        return(rse)
    }

    colnames(rse) <- make.unique(barcodes, sep = "_")
    cat("TCGA sample names set from", barcode_col, "\n")
    rse
}

use_gtex_barcodes <- function(rse) {
    meta <- as.data.frame(colData(rse))
    barcode_col <- first_col(meta, c(
        "external_id",
        "sra.sample",
        "gtex.smtsd",
        "gtex_subjid"
    ))
    if (!is.null(barcode_col)) {

        colnames(rse) <- make.unique(
            as.character(meta[[barcode_col]]),
            sep = "_"
        )
        cat("GTEx sample names set from:", barcode_col, "\n")

    } else {

        cat("WARNING: no GTEx barcode column found; keeping UUID sample names.\n")
    }
    rse
}

project_table <- read.delim("project_table.tsv", row.names = 1)
project_info <- subset(project_table, project == data_source)
if (nrow(project_info) != 1) {
    stop("Expected one project row for ", data_source, "; found ", nrow(project_info))
}

is_tcga <- grepl("tcga", project_info$file_source, ignore.case = TRUE)
is_gtex <- grepl("gtex", project_info$file_source, ignore.case = TRUE)
cat("Starting recount3:", data_source, "| source:", project_info$file_source,
    "| normalize:", normalize, "\n")

rse <- recount3::create_rse(project_info, type = "gene", annotation = "gencode_v29")
if (is.null(rse) || ncol(rse) == 0) stop("create_rse returned no samples for ", data_source)

assay(rse, "counts") <- recount3::transform_counts(rse)
if (is_tcga) {
    rse <- use_tcga_barcodes(filter_tcga(rse, tissue_type))
} else if (is_gtex) {
    cat("GTEx project: tissue_type is ignored.\n")
}

raw_counts <- as.data.frame(assay(rse, "counts"), check.names = FALSE)
sample_meta <- as.data.frame(colData(rse))
gene_annot <- as.data.frame(rowData(rse))
rownames(sample_meta) <- colnames(rse)

## saves the raw integer count matrix to a file
write_tab(raw_counts, out_raw)
## saves TPM-normalized counts only if user enabled normalization
if (normalize) write_tab(as.data.frame(recount::getTPM(rse), check.names = FALSE), out_tpm)
## saves sample metadata (colData)
write_tab(sample_meta, out_sample)
## saves gene annotations (rowData) using GENCODE v29
write_tab(gene_annot, out_gene)
cat("Done.\n")
#end raw
